const t=JSON.parse(`{"key":"v-3aec6c91","path":"/vanblog/Linux%E5%91%BD%E4%BB%A4%E8%A1%8C%E2%80%9C-%E2%80%9D%E7%9A%84%E5%90%AB%E4%B9%89.html","title":"简介","lang":"zh-CN","frontmatter":{"description":"简介 在 Linux 命令行中，\\"-\\" 有以下几种含义： 作为命令选项（option）的前缀： 命令通常具有一些选项，用于指定命令的不同行为。选项通常以单个短横线（\\"-\\"）作为前缀，后面跟随一个字母或一些字母的组合。例如，\\"ls -l\\" 中的 \\"-l\\" 选项用于显示长格式的文件列表。 作为标准输入（stdin）的代表： 当使用短横线作为命令的参数时，它表示将标准输入作为命令的输入。例如，\\"cat -\\" 命令表示将标准输入的内容作为输出。 作为特殊文件名的代表： 在 Linux 中，有两个特殊的文件名：一个是单个短横线（\\"-\\"），另一个是双短横线（\\"--\\"）。单个短横线表示标准输入或标准输出，双短横线则表示命令选项的结束。例如，\\"cp -\\" 命令表示将标准输入的内容复制到目标文件，而\\"cp --\\" 命令则表示选项的结束。 作为变量名的前缀： 在 Linux 中，变量名可以以一个短横线作为前缀。这种用法通常用于表示选项的默认值。例如，\\"$-option\\" 变量表示选项的默认值。 总之，短横线在 Linux 命令行中是一个非常常见的符号，具有多种不同的含义，需要根据上下文具体理解。","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/vanblog/Linux%E5%91%BD%E4%BB%A4%E8%A1%8C%E2%80%9C-%E2%80%9D%E7%9A%84%E5%90%AB%E4%B9%89.html"}],["meta",{"property":"og:site_name","content":"Kevin2li's Blog"}],["meta",{"property":"og:title","content":"简介"}],["meta",{"property":"og:description","content":"简介 在 Linux 命令行中，\\"-\\" 有以下几种含义： 作为命令选项（option）的前缀： 命令通常具有一些选项，用于指定命令的不同行为。选项通常以单个短横线（\\"-\\"）作为前缀，后面跟随一个字母或一些字母的组合。例如，\\"ls -l\\" 中的 \\"-l\\" 选项用于显示长格式的文件列表。 作为标准输入（stdin）的代表： 当使用短横线作为命令的参数时，它表示将标准输入作为命令的输入。例如，\\"cat -\\" 命令表示将标准输入的内容作为输出。 作为特殊文件名的代表： 在 Linux 中，有两个特殊的文件名：一个是单个短横线（\\"-\\"），另一个是双短横线（\\"--\\"）。单个短横线表示标准输入或标准输出，双短横线则表示命令选项的结束。例如，\\"cp -\\" 命令表示将标准输入的内容复制到目标文件，而\\"cp --\\" 命令则表示选项的结束。 作为变量名的前缀： 在 Linux 中，变量名可以以一个短横线作为前缀。这种用法通常用于表示选项的默认值。例如，\\"$-option\\" 变量表示选项的默认值。 总之，短横线在 Linux 命令行中是一个非常常见的符号，具有多种不同的含义，需要根据上下文具体理解。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-05-22T06:31:47.000Z"}],["meta",{"property":"article:author","content":"Kevin2li"}],["meta",{"property":"article:modified_time","content":"2023-05-22T06:31:47.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"简介\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2023-05-22T06:31:47.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Kevin2li\\",\\"url\\":\\"https://blog.kevin2li.top\\"}]}"]]},"headers":[],"git":{"createdTime":1684730003000,"updatedTime":1684737107000,"contributors":[{"name":"kevin2li","email":"kevin2li@qq.com","commits":3}]},"readingTime":{"minutes":1.97,"words":591},"filePathRelative":"vanblog/Linux命令行“-”的含义.md","localizedDate":"2023年5月22日","excerpt":"<h1> 简介</h1>\\n<p>在 Linux 命令行中，\\"-\\" 有以下几种含义：</p>\\n<ol>\\n<li><strong>作为命令选项（option）的前缀：</strong></li>\\n</ol>\\n<p>命令通常具有一些选项，用于指定命令的不同行为。选项通常以单个短横线（\\"-\\"）作为前缀，后面跟随一个字母或一些字母的组合。例如，\\"ls -l\\" 中的 \\"-l\\" 选项用于显示长格式的文件列表。</p>\\n<ol start=\\"2\\">\\n<li><strong>作为标准输入（stdin）的代表：</strong></li>\\n</ol>\\n<p>当使用短横线作为命令的参数时，它表示将标准输入作为命令的输入。例如，\\"cat -\\" 命令表示将标准输入的内容作为输出。</p>\\n<ol start=\\"3\\">\\n<li><strong>作为特殊文件名的代表：</strong></li>\\n</ol>\\n<p>在 Linux 中，有两个特殊的文件名：一个是单个短横线（\\"-\\"），另一个是双短横线（\\"--\\"）。单个短横线表示标准输入或标准输出，双短横线则表示命令选项的结束。例如，\\"cp -\\" 命令表示将标准输入的内容复制到目标文件，而\\"cp --\\" 命令则表示选项的结束。</p>\\n<ol start=\\"4\\">\\n<li><strong>作为变量名的前缀：</strong></li>\\n</ol>\\n<p>在 Linux 中，变量名可以以一个短横线作为前缀。这种用法通常用于表示选项的默认值。例如，\\"$-option\\" 变量表示选项的默认值。</p>\\n<p>总之，短横线在 Linux 命令行中是一个非常常见的符号，具有多种不同的含义，需要根据上下文具体理解。</p>\\n","autoDesc":true}`);export{t as data};
